def range_summary(nums):
    if not nums:
        return ''

    nums.sort()
    ranges = []
    start = end = nums[0]

    for num in nums[1:]:
        if num == end + 1:
            end = num
        else:
            if start == end:
                ranges.append(str(start))
            else:
                ranges.append(f'{start}-{end}')
            start = end = num

    if start == end:
        ranges.append(str(start))
    else:
        ranges.append(f'{start}-{end}')

    return ', '.join(ranges)
